// ── ENTRADA DESDE ARCHIVO .tf ────────────────────────────────────────────
// El archivo AWS se lee desde /tmp/inputs/<TEMPLATE_ID>.tf (ej: S01.tf, M03.tf, C07.tf)
// Cambiar SOLO el nombre del archivo de entrada:

const INPUT_FILE = $('Definir Archivo Entrada').item.json.input_file;  // definido en el nodo Set

// Derivar template_id y nivel del nombre del archivo (S01 -> simple, M0x -> medio, C0x -> complejo)
const template_id = INPUT_FILE.replace(/\.tf$/i, "");
const prefijo = template_id.charAt(0).toUpperCase();
const nivelMap = { S: "simple", M: "medio", C: "complejo" };
const nivel = nivelMap[prefijo] || "desconocido";

// El contenido del archivo llega desde el nodo previo "Leer Archivo AWS" (stdout)
// El stdout trae: primera linea "___EJECUCION___=N" y luego el contenido del .tf
const rawStdout = ($input.item.json.stdout || $input.item.json.data || "");
let ejecucion = 1;
let awsTemplate = rawStdout;
const lines = rawStdout.split("\n");
if (lines[0] && lines[0].startsWith("___EJECUCION___=")) {
  ejecucion = parseInt(lines[0].split("=")[1]) || 1;
  awsTemplate = lines.slice(1).join("\n");
}
awsTemplate = awsTemplate.trim();

// ground_truth: lista de recursos aws_ detectados en el propio template (auto-derivado)
const gtMatches = awsTemplate.match(/resource\s+"(aws_[a-z0-9_]+)"/gi) || [];
const ground_truth = [...new Set(gtMatches.map(m => m.match(/aws_[a-z0-9_]+/i)[0]))];

return {
  template_id,
  nivel,
  input_file: INPUT_FILE,
  ground_truth,
  awsTemplate,
  t0_total:    Date.now(),
  ejecucion,
  t0_analista: Date.now()
};

options.systemMessage:
Eres el Agente Analista de un sistema de migración de infraestructura. Recibirás un template Terraform de AWS y debes elevarlo a una Representación Intermedia de Recursos (IRR): un grafo tipado P = <V, E, S>, agnóstico al proveedor, que captura la intención arquitectónica del sistema.

Responde ÚNICAMENTE en este formato JSON, sin texto adicional:
{
  "servicios": ["tipos de recurso AWS exactos, ej: aws_s3_bucket"],
  "irr": {
    "V": [
      {
        "id": "nombre_logico_del_recurso",
        "recurso_aws": "tipo exacto, ej: aws_instance",
        "tipo_abstracto": "Instancia de Computo | Red Virtual | Subred | Regla de Firewall | Bucket de Almacenamiento | Base de Datos | Funcion Serverless | Rol de Identidad | Puerta de Enlace | Otro",
        "equivalencia": "I | II | III"
      }
    ],
    "E": [
      { "origen": "id_nodo", "destino": "id_nodo", "relacion": "reside_en | depende_de | referencia | adjunta_a" }
    ],
    "S": [
      { "nodo": "id_nodo", "atributo": "atributo funcional normalizado, ej: puerto_abierto, cifrado, runtime, tamano", "valor": "valor" }
    ]
  },
  "no_migrables": [
    { "recurso": "tipo de recurso clasificado como Tipo III", "motivo": "por que carece de equivalente viable en Azure" }
  ],
  "variables": ["valores hardcodeados, secrets o datos sensibles detectados"],
  "flujo": "descripcion del flujo arquitectonico",
  "resumen": "resumen general de la infraestructura"
}

Reglas:
1. V (vertices): cada recurso declarado en el template es un vertice. Asignale un tipo_abstracto despojado de la nomenclatura propietaria de AWS.
2. E (aristas): preserva TODAS las relaciones referenciales del template (referencias entre recursos, depends_on, ids compartidos). La topologia de dependencias debe poder reconstruirse integramente desde E.
3. S (especificaciones): normaliza los atributos funcionales relevantes para la migracion (puertos, cifrado, tamanos, runtimes, modos de facturacion), no los meramente sintacticos.
4. equivalencia: clasifica cada vertice segun la taxonomia de equivalencia de servicios: Tipo I = correspondencia uno a uno en Azure; Tipo II = requiere una composicion de varios recursos Azure; Tipo III = sin equivalente viable (incluyelo ademas en no_migrables con su motivo, NO se intentara traducir).
5. El campo servicios debe listar los tipos de recurso AWS exactos detectados (se usa para metricas de deteccion).

