// ── OE1: métricas del Agente Analista ────────────────────────────────────
const analista_output = $input.item.json.output || "";
const t0 = $('Input Template AWS').item.json.t0_analista || Date.now();
const t1 = Date.now();

// Parsear JSON del Analista (con fallback a regex)
let servicios_detectados = [];
try {
  const clean = analista_output
    .replace(/```json\n?/g, "")
    .replace(/```\n?/g,     "")
    .trim();
  const parsed = JSON.parse(clean);
  servicios_detectados = parsed.servicios || [];
} catch (_) {
  const matches = analista_output.match(/aws_\w+/g) || [];
  servicios_detectados = [...new Set(matches)];
}

// Precision / Recall / F1 vs ground truth
const ground_truth = $('Input Template AWS').item.json.ground_truth || [];
const gt  = new Set(ground_truth);
const det = new Set(servicios_detectados);

const TP = [...gt].filter(r => det.has(r)).length;
const FP = [...det].filter(r => !gt.has(r)).length;
const FN = [...gt].filter(r => !det.has(r)).length;

const precision = (TP + FP) > 0 ? TP / (TP + FP) : 0;
const recall    = (TP + FN) > 0 ? TP / (TP + FN) : 0;
const f1 = (precision + recall) > 0
  ? 2 * precision * recall / (precision + recall) : 0;

// ── TOKENS DEL ANALISTA (estimado chars/4; usa real si la API lo reporta) ──
const analistaFull = $('AI Agent-Analista').item.json;
let tokens_analista;
if (analistaFull.tokenUsage && analistaFull.tokenUsage.totalTokens) {
  tokens_analista = analistaFull.tokenUsage.totalTokens;
} else if (analistaFull.usage && analistaFull.usage.total_tokens) {
  tokens_analista = analistaFull.usage.total_tokens;
} else {
  const inTxt  = $('Input Template AWS').item.json.awsTemplate || "";
  const outTxt = analistaFull.output || "";
  tokens_analista = Math.round((inTxt.length + outTxt.length) / 4);
}

return {
  // Pasar análisis al Arquitecto
  output: analista_output,

  // OE1
  metricas_oe1: {
    template_id: $('Input Template AWS').item.json.template_id,
    ground_truth,
    servicios_detectados,
    TP, FP, FN,
    precision: Math.round(precision * 10000) / 10000,
    recall:    Math.round(recall    * 10000) / 10000,
    f1:        Math.round(f1        * 10000) / 10000
  },

  // OE3: eficiencia computacional
  tiempo_analista_ms: t1 - t0,
  tokens_analista,
  t0_arquitecto_ref:  Date.now()
};

// Primer intento: usa el análisis del Analista
// Reintentos:    usa el error del Validador con corrección mínima y dirigida
const hasFeedback = $json.terraformError ? true : false;

let prompt;
if (hasFeedback) {
  prompt = `El template anterior falló con este error de Terraform:
${$json.errorResumen || $json.terraformError}

Template anterior:
${$json.previousTemplate}

Corrige el template resolviendo EXACTAMENTE el error indicado.
Haz cambios mínimos y dirigidos, no reescribas todo el template.`;
} else {
  prompt = `Genera el template Terraform Azure a partir de la siguiente Representación Intermedia de Recursos (IRR) de la infraestructura AWS:
${$json.output}

Instrucciones de proyección:
- Proyecta cada vértice (V) al recurso azurerm correspondiente según su tipo_abstracto, preservando íntegramente la topología de dependencias (E) y los atributos funcionales (S).
- Para vértices de equivalencia Tipo II, genera la composición completa de recursos Azure necesaria (p. ej., una instancia AWS se proyecta como VM + interfaz de red + grupo de seguridad).
- Los recursos listados en no_migrables (Tipo III) NO deben traducirse: decláralos como comentario HCL indicando el recurso y el motivo.`;
}

return {
  prompt,
  t0_arquitecto_iter: Date.now()
};

const templateContent = $input.item.json.output;

const cleanTemplate = templateContent
  .replace(/```hcl\n?/g,       "")
  .replace(/```terraform\n?/g, "")
  .replace(/```\n?/g,          "")
  .trim();

const attempt = $runIndex + 1;

// Recuperar el t0 de ESTA iteracion: 'Preparar Prompt Arquitecto' corre justo antes
// del Arquitecto en cada vuelta del bucle, asi que .last() da el inicio correcto.
let t0;
try {
  t0 = $('Preparar Prompt Arquitecto').last().json.t0_arquitecto_iter;
} catch(e) {
  t0 = Date.now();
}
if (!t0) t0 = Date.now();


// ── TOKENS DEL ARQUITECTO (estimado chars/4; usa real si la API lo reporta) ──
const arqFull = $input.item.json;
let tokens_arquitecto;
if (arqFull.tokenUsage && arqFull.tokenUsage.totalTokens) {
  tokens_arquitecto = arqFull.tokenUsage.totalTokens;
} else if (arqFull.usage && arqFull.usage.total_tokens) {
  tokens_arquitecto = arqFull.usage.total_tokens;
} else {
  const promptTxt = $('Preparar Prompt Arquitecto').last().json.prompt || "";
  tokens_arquitecto = Math.round((promptTxt.length + (arqFull.output||"").length) / 4);
}

return {
  templateContent: cleanTemplate,
  tokens_arquitecto,
  attempt,
  tiempo_arquitecto_ms: Date.now() - t0,
  t0_validador: Date.now()
};

// ── Consolida los DATOS CRUDOS del intento (para resultados.txt) ────────
const t0_total = $('Input Template AWS').item.json.t0_total;
const t1_total = Date.now();
const template_id = $('Input Template AWS').item.json.template_id;
const nivel       = $('Input Template AWS').item.json.nivel;

// Salida del auditor (HTTP JSON): checkov, tfsec, tflint, infracost
const audit = $input.item.json || {};
const checkov   = parseInt(audit.checkov_failed) || 0;
const tfsec     = parseInt(audit.tfsec_issues)   || 0;
const tflint    = parseInt(audit.tflint_issues)  || 0;
const infracost = (audit.infracost_monthly === null || audit.infracost_monthly === undefined)
                    ? "NA" : parseFloat(audit.infracost_monthly);

// ── TIEMPOS POR AGENTE ──
const tiempo_analista_ms = $('Parsear Output Analista').item.json.tiempo_analista_ms || 0;

const templatesArray = $('Guardar Template').all();
const lastTpl = templatesArray.length ? templatesArray[templatesArray.length - 1] : { json: {} };
// Arquitecto: tiempo SUMADO sobre todas las iteraciones del ciclo
const tiempo_arquitecto_ms = templatesArray.reduce((s, it) => s + (it.json.tiempo_arquitecto_ms || 0), 0);

// Validador: tiempo SUMADO sobre todas las iteraciones
const valArray = $('AI Agent-Validador').all();
let tiempo_validador_ms = 0;
for (let i = 0; i < templatesArray.length; i++) {
  const t0v = templatesArray[i].json.t0_validador;
  if (!t0v) continue;
  const tFin = (i + 1 < templatesArray.length)
                 ? (templatesArray[i + 1].json.t0_validador || Date.now())
                 : Date.now();
  tiempo_validador_ms += Math.max(0, tFin - t0v);
}

// ── TOKENS (estimados por caracteres ~4 chars/token; usa tokenUsage real si esta disponible) ──
const tokens_analista   = $('Parsear Output Analista').item.json.tokens_analista || 0;
// Arquitecto: suma sobre iteraciones
const tokens_arquitecto = templatesArray.reduce((s, it) => s + (it.json.tokens_arquitecto || 0), 0);
// Validador: suma sobre iteraciones (real si hay tokenUsage; si no, estima entrada+salida)
let tokens_validador = 0;
for (let i = 0; i < valArray.length; i++) {
  const vf = valArray[i].json;
  if (vf.tokenUsage && vf.tokenUsage.totalTokens) {
    tokens_validador += vf.tokenUsage.totalTokens;
  } else if (vf.usage && vf.usage.total_tokens) {
    tokens_validador += vf.usage.total_tokens;
  } else {
    const entrada = (templatesArray[i] && templatesArray[i].json.templateContent) || "";
    const salida  = vf.output || "";
    tokens_validador += Math.round((entrada.length + salida.length) / 4);
  }
}
const tokens_totales = tokens_analista + tokens_arquitecto + tokens_validador;

// Iteraciones y convergencia
const iteraciones = lastTpl.json.attempt || 1;
const convergio   = 1;

// CodeBERTScore F1 calculado por el auditor (comparando output vs esperado)
const cbs_f1 = (audit.cbs_f1 === null || audit.cbs_f1 === undefined) ? "NA" : audit.cbs_f1;

// DSR: llego a Consolidar => terraform plan OK => despliegue exitoso
const dsr = 1;

// Tiempos en segundos
const tiempo_e2e_s   = parseFloat(((t1_total - t0_total) / 1000).toFixed(1));
const t_analista_s   = parseFloat((tiempo_analista_ms   / 1000).toFixed(1));
const t_arquitecto_s = parseFloat((tiempo_arquitecto_ms / 1000).toFixed(1));
const t_validador_s  = parseFloat((tiempo_validador_ms  / 1000).toFixed(1));

// ── COSTO USD (estimado desde tokens totales) ──
// Precio mixto aproximado Claude Sonnet: ~$6 por millon de tokens.
const PRECIO_POR_MILLON = 6.0;
const cost_usd = parseFloat(((tokens_totales / 1000000) * PRECIO_POR_MILLON).toFixed(6));

return {
  template_id,
  nivel,
  dsr,
  t_analista_s,
  t_arquitecto_s,
  t_validador_s,
  tiempo_e2e_s,
  checkov,
  tfsec,
  tflint,
  cbs_f1,
  infracost,
  iteraciones,
  convergio,
  tokens_analista,
  tokens_arquitecto,
  tokens_validador,
  tokens_totales,
  cost_usd
};

// ── Registra el intento FALLIDO (dsr=0) como fila cruda ─────────────────
const template_id = $('Input Template AWS').item.json.template_id;
const nivel       = $('Input Template AWS').item.json.nivel;
const t0_total    = $('Input Template AWS').item.json.t0_total;

// Tiempos por agente (sumados sobre iteraciones)
const tiempo_analista_ms = $('Parsear Output Analista').item.json.tiempo_analista_ms || 0;
const templatesArray = $('Guardar Template').all();
const tiempo_arquitecto_ms = templatesArray.reduce((s, it) => s + (it.json.tiempo_arquitecto_ms || 0), 0);

const valArray = $('AI Agent-Validador').all();
let tiempo_validador_ms = 0;
for (let i = 0; i < templatesArray.length; i++) {
  const t0v = templatesArray[i].json.t0_validador;
  if (!t0v) continue;
  const tFin = (i + 1 < templatesArray.length)
                 ? (templatesArray[i + 1].json.t0_validador || Date.now())
                 : Date.now();
  tiempo_validador_ms += Math.max(0, tFin - t0v);
}

// Tokens (estimados; suma sobre iteraciones)
const tokens_analista   = $('Parsear Output Analista').item.json.tokens_analista || 0;
const tokens_arquitecto = templatesArray.reduce((s, it) => s + (it.json.tokens_arquitecto || 0), 0);
let tokens_validador = 0;
for (let i = 0; i < valArray.length; i++) {
  const vf = valArray[i].json;
  if (vf.tokenUsage && vf.tokenUsage.totalTokens) tokens_validador += vf.tokenUsage.totalTokens;
  else if (vf.usage && vf.usage.total_tokens)     tokens_validador += vf.usage.total_tokens;
  else {
    const entrada = (templatesArray[i] && templatesArray[i].json.templateContent) || "";
    const salida  = vf.output || "";
    tokens_validador += Math.round((entrada.length + salida.length) / 4);
  }
}
const tokens_totales = tokens_analista + tokens_arquitecto + tokens_validador;
const cost_usd = parseFloat(((tokens_totales / 1000000) * 6.0).toFixed(6));

return {
  template_id,
  nivel,
  dsr: 0,
  t_analista_s:   parseFloat((tiempo_analista_ms/1000).toFixed(1)),
  t_arquitecto_s: parseFloat((tiempo_arquitecto_ms/1000).toFixed(1)),
  t_validador_s:  parseFloat((tiempo_validador_ms/1000).toFixed(1)),
  tiempo_e2e_s:   parseFloat(((Date.now()-t0_total)/1000).toFixed(1)),
  checkov:   "NA",
  tfsec:     "NA",
  tflint:    "NA",
  cbs_f1:    "NA",
  infracost: "NA",
  iteraciones: ($json.attempt || 5) - 1,
  convergio: 0,
  tokens_analista,
  tokens_arquitecto,
  tokens_validador,
  tokens_totales,
  cost_usd
};

parameters.text:
=Valida el siguiente template Terraform de Azure generado por el Arquitecto y determina si es apto para despliegue. Si contiene errores, diagnostícalos para su corrección.

Template a validar:
{{ $json.templateContent }}

parameters.jsCode:
// ── OE3: feedback estructurado + control de iteraciones ─────────────────
// Usamos $runIndex para saber exactamente cuántas veces ha fallado este nodo
const currentAttempt = $runIndex + 1; 
const MAX_ATTEMPTS   = 5;
const limite_alcanzado = currentAttempt >= MAX_ATTEMPTS;

const terraformOutput = $input.item.json.stdout || "";

// Extraer líneas de error relevantes
const errorLines = terraformOutput
  .split("\n")
  .filter(l => l.toLowerCase().includes("error"))
  .slice(0, 15)
  .join("\n");

return {
  attempt:          currentAttempt + 1,
  terraformError:   terraformOutput,
  errorResumen:     errorLines || terraformOutput.substring(0, 800),
  // Usamos .last() para asegurar que leemos el template de esta última iteración
  previousTemplate: $('Guardar Template').last().json.templateContent,
  d_iteracion:      currentAttempt,
  limite_alcanzado
};
